import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import Alert from '../../components/common/Alert';
import Badge from '../../components/common/Badge';
import { formatDate, formatCurrency, getInitials } from '../../utils/formatters';
import employeeService from '../../services/employeeService';
import './ProfilePage.css';

const ROLE_LABELS = { admin: 'Admin', manager: 'Manager', employee: 'Angajat' };

export default function ProfilePage() {
  const { currentUser, refreshToken } = useAuth();
  const [editing, setEditing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState('');
  const [error, setError] = useState('');

  const [form, setForm] = useState({
    firstName: currentUser?.firstName || '',
    lastName: currentUser?.lastName || '',
    phone: currentUser?.phone || '',
    position: currentUser?.position || '',
    avatar: currentUser?.avatar || '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSave = async () => {
    if (!form.firstName || !form.lastName) return setError('Prenumele și numele sunt obligatorii.');
    setSaving(true);
    setError('');
    setSuccess('');
    try {
      await employeeService.update(currentUser.id, form);
      setSuccess('Profilul a fost actualizat cu succes.');
      setEditing(false);
      await refreshToken?.();
    } catch (err) {
      setError(err.response?.data?.message || 'Eroare la salvare.');
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    setForm({
      firstName: currentUser?.firstName || '',
      lastName: currentUser?.lastName || '',
      phone: currentUser?.phone || '',
      position: currentUser?.position || '',
      avatar: currentUser?.avatar || '',
    });
    setEditing(false);
    setError('');
  };

  if (!currentUser) return null;

  return (
    <div className="profile-page">
      <h1>Profilul meu</h1>

      {success && <Alert type="success">{success}</Alert>}
      {error && <Alert type="danger">{error}</Alert>}

      <div className="profile-grid">
        {/* Identity Card */}
        <Card className="profile-identity-card">
          <Card.Body>
            <div className="profile-avatar-section">
              {currentUser.avatar ? (
                <img src={currentUser.avatar} alt="avatar" className="profile-avatar-img" />
              ) : (
                <div className="profile-avatar-placeholder">
                  {getInitials(currentUser.firstName, currentUser.lastName)}
                </div>
              )}
              <div>
                <h2 className="profile-fullname">{currentUser.firstName} {currentUser.lastName}</h2>
                <p className="profile-email">{currentUser.email}</p>
                <Badge color={currentUser.role === 'admin' ? 'danger' : currentUser.role === 'manager' ? 'warning' : 'info'}>
                  {ROLE_LABELS[currentUser.role]}
                </Badge>
              </div>
            </div>

            <div className="profile-meta">
              <div className="profile-meta-row">
                <span>📋 Poziție</span>
                <strong>{currentUser.position || '—'}</strong>
              </div>
              <div className="profile-meta-row">
                <span>📞 Telefon</span>
                <strong>{currentUser.phone || '—'}</strong>
              </div>
              <div className="profile-meta-row">
                <span>📅 Angajat din</span>
                <strong>{currentUser.hireDate ? formatDate(currentUser.hireDate) : '—'}</strong>
              </div>
              <div className="profile-meta-row">
                <span>🏢 Departament</span>
                <strong>{currentUser.Department?.name || '—'}</strong>
              </div>
              <div className="profile-meta-row">
                <span>🕐 Tură</span>
                <strong>{currentUser.Shift ? `${currentUser.Shift.name} (${currentUser.Shift.startTime}–${currentUser.Shift.endTime})` : '—'}</strong>
              </div>
              <div className="profile-meta-row">
                <span>💰 Salariu bază</span>
                <strong>{currentUser.baseSalary ? formatCurrency(currentUser.baseSalary) : '—'}</strong>
              </div>
              <div className="profile-meta-row">
                <span>🏖 Concediu rămas</span>
                <strong>{currentUser.annualLeaveBalance ?? 0} zile</strong>
              </div>
              <div className="profile-meta-row">
                <span>🤒 Concediu medical rămas</span>
                <strong>{currentUser.sickLeaveBalance ?? 0} zile</strong>
              </div>
            </div>

            {!editing && (
              <Button variant="primary" fullWidth onClick={() => setEditing(true)} className="mt-4">
                Editează profil
              </Button>
            )}
          </Card.Body>
        </Card>

        {/* Edit Form */}
        {editing && (
          <Card>
            <Card.Header><h3>Editează informații</h3></Card.Header>
            <Card.Body>
              <div className="profile-form">
                <Input label="Prenume *" name="firstName" value={form.firstName} onChange={handleChange} />
                <Input label="Nume *" name="lastName" value={form.lastName} onChange={handleChange} />
                <Input label="Telefon" name="phone" value={form.phone} onChange={handleChange} placeholder="07xx xxx xxx" />
                <Input label="Poziție / Titlu job" name="position" value={form.position} onChange={handleChange} />
                <Input label="URL Avatar" name="avatar" value={form.avatar} onChange={handleChange} placeholder="https://..." />
                {form.avatar && (
                  <div className="avatar-preview">
                    <img src={form.avatar} alt="preview" onError={e => e.target.style.display = 'none'} />
                  </div>
                )}
                <div className="profile-form-actions">
                  <Button variant="secondary" onClick={handleCancel}>Anulează</Button>
                  <Button variant="primary" loading={saving} onClick={handleSave}>Salvează</Button>
                </div>
              </div>
            </Card.Body>
          </Card>
        )}
      </div>
    </div>
  );
}
